      fun ?phoneNumberCountryCode ->
        fun ?phoneNumberType ->
          fun () -> { phoneNumber; phoneNumberCountryCode; phoneNumberType }
    let to_value x =
      structure_to_value
        [("PhoneNumber", (Option.map x.phoneNumber ~f:PhoneNumber.to_value));
