          (Option.map x.phoneNumberCountryCode
             ~f:PhoneNumberCountryCode.to_value));
        ("PhoneNumberType",
          (Option.map x.phoneNumberType ~f:PhoneNumberType.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let phoneNumberType =
        (Option.map ~f:PhoneNumberType.of_xml)
          (Xml.child xml_arg0 "PhoneNumberType") in
      let phoneNumberCountryCode =
        (Option.map ~f:PhoneNumberCountryCode.of_xml)
          (Xml.child xml_arg0 "PhoneNumberCountryCode") in
      let phoneNumber =
        (Option.map ~f:PhoneNumber.of_xml) (Xml.child xml_arg0 "PhoneNumber") in
      make ?phoneNumberType ?phoneNumberCountryCode ?phoneNumber ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let phoneNumberType =
        field_map json__ "PhoneNumberType" PhoneNumberType.of_json in
      let phoneNumberCountryCode =
