module BatchAssociateAnalyticsDataSetRequest =
  struct
    type nonrec t =
      {
      instanceId: InstanceId.t
        [@ocaml.doc
          "The identifier of the Amazon Connect instance. You can find the instance ID in the Amazon Resource Name (ARN) of the instance."];
      dataSetIds: DataSetIds.t
        [@ocaml.doc "An array of dataset identifiers to associate."];
      targetAccountId: AWSAccountId.t option
        [@ocaml.doc
          "The identifier of the target account. Use to associate a dataset to a different account than the one containing the Amazon Connect instance. If not specified, by default this value is the Amazon Web Services account that has the Amazon Connect instance."]}
    let context_ = "BatchAssociateAnalyticsDataSetRequest"
    let make ?targetAccountId =
      fun ~instanceId ->
        fun ~dataSetIds ->
          fun () -> { targetAccountId; instanceId; dataSetIds }
    let to_value x =
      structure_to_value
        [("InstanceId", (Some (InstanceId.to_value x.instanceId)));
        ("DataSetIds", (Some (DataSetIds.to_value x.dataSetIds)));
        ("TargetAccountId",
          (Option.map x.targetAccountId ~f:AWSAccountId.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let targetAccountId =
        (Option.map ~f:AWSAccountId.of_xml)
          (Xml.child xml_arg0 "TargetAccountId") in
      let dataSetIds =
        DataSetIds.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "DataSetIds") in
      let instanceId =
        InstanceId.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "InstanceId") in
      make ?targetAccountId ~dataSetIds ~instanceId ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let targetAccountId =
        field_map json__ "TargetAccountId" AWSAccountId.of_json in
      let dataSetIds = field_map_exn json__ "DataSetIds" DataSetIds.of_json in
      let instanceId = field_map_exn json__ "InstanceId" InstanceId.of_json in
      make ?targetAccountId ~dataSetIds ~instanceId ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Associates a list of analytics datasets for a given Amazon Connect instance to a target account. You can associate multiple datasets in a single call."]
